mapper.select:
SELECT p.post_id, u.user_id, u.nickname, u.profile_image, p.content, p.like_count, p.created_at FROM ( SELECT gm.user_id FROM group_members gm JOIN user_groups ug ON ug.group_id = gm.group_id WHERE gm.group_id IN ( SELECT m.group_id FROM group_members m JOIN user_groups my_ug ON my_ug.group_id = m.group_id WHERE m.user_id = #{userId} AND my_ug.deleted_at IS NULL ) AND ug.deleted_at IS NULL UNION SELECT f.followee user_id FROM user_follow f WHERE f.follower = #{userId} ) r JOIN users u ON u.user_id = r.user_id JOIN posts p ON p.user_id = u.user_id WHERE u.deleted_at IS NULL AND p.deleted_at IS NULL
AND (p.created_at, p.post_id) < (#{createdAt}, #{postId})
ORDER BY p.created_at DESC, p.post_id DESC LIMIT #{size}

SELECT p.post_id, u.user_id, u.nickname, u.profile_image, p.content, p.like_count, p.created_at FROM posts p JOIN users u ON u.user_id = p.user_id WHERE p.deleted_at IS NULL AND u.deleted_at IS NULL
AND (p.created_at, p.post_id) < (#{createdAt}, #{postId})
ORDER BY p.created_at DESC, p.post_id DESC LIMIT #{size}

SELECT i.post_id, i.image_url FROM post_images i JOIN posts p ON p.post_id = i.post_id WHERE i.deleted_at IS NULL AND p.deleted_at IS NULL AND i.post_id IN
#{postId}
ORDER BY i.post_id, i.created_at

